import java.util.*;

public static long[] solve(long[] nums, long[][] queries) {
    // Precompute popcount-depth for numbers up to 1e15, but since it's not feasible,
    // we'll compute it on the fly with memoization.
    Map<Long, Integer> depthCache = new HashMap<>();
    depthCache.put(1L, 0);

    // Function to compute popcount
    Function<Long, Integer> popcount = (x) -> {
        int count = 0;
        while (x != 0) {
            count += (x & 1);
            x >>>= 1;
        }
        return count;
    };

    // Function to compute popcount-depth with memoization
    Function<Long, Integer> getDepth = new Function<Long, Integer>() {
        @Override
        public Integer apply(Long x) {
            if (depthCache.containsKey(x)) {
                return depthCache.get(x);
            }
            int nextPop = popcount.apply(x);
            int depth = 1 + getDepth.apply((long)nextPop);
            depthCache.put(x, depth);
            return depth;
        }
    };

    // Process queries
    List<Long> answerList = new ArrayList<>();
    for (long[] query : queries) {
        if (query[0] == 1) {
            // Query type 1: [1, l, r, k]
            int l = (int)query[1];
            int r = (int)query[2];
            int k = (int)query[3];
            long count = 0;
            for (int i = l; i <= r; i++) {
                int depth = getDepth.apply(nums[i]);
                if (depth == k) {
                    count++;
                }
            }
            answerList.add(count);
        } else if (query[0] == 2) {
            // Query type 2: [2, idx, val]
            int idx = (int)query[1];
            long val = query[2];
            nums[idx] = val;
        }
    }

    // Convert answerList to long[]
    long[] answer = new long[answerList.size()];
    for (int i = 0; i < answer.length; i++) {
        answer[i] = answerList.get(i);
    }
    return answer;
}
