import java.util.*;

public static long[] solve(long[] nums, long[][] queries) {
    // Precompute popcount-depth for numbers up to 1e15
    // Since popcount-depth is logarithmic, we can memoize it
    Map<Long, Integer> depthMap = new HashMap<>();
    depthMap.put(1L, 0);

    List<Long> answerList = new ArrayList<>();
    List<Integer> answerIndices = new ArrayList<>();

    for (int i = 0; i < queries.length; i++) {
        long[] query = queries[i];
        if (query[0] == 1) {
            answerIndices.add(i);
        }
    }

    long[] answer = new long[answerIndices.size()];
    int answerIdx = 0;

    for (int i = 0; i < queries.length; i++) {
        long[] query = queries[i];
        if (query[0] == 1) {
            // Type 1 query: count in [l, r] with depth k
            int l = (int) query[1];
            int r = (int) query[2];
            int k = (int) query[3];
            long count = 0;
            for (int j = l; j <= r; j++) {
                long num = nums[j];
                int depth = computeDepth(num, depthMap);
                if (depth == k) {
                    count++;
                }
            }
            answer[answerIdx++] = count;
        } else if (query[0] == 2) {
            // Type 2 query: update nums[idx] to val
            int idx = (int) query[1];
            long val = query[2];
            nums[idx] = val;
        }
    }

    return answer;
}

private static int computeDepth(long num, Map<Long, Integer> depthMap) {
    if (depthMap.containsKey(num)) {
        return depthMap.get(num);
    }

    List<Long> sequence = new ArrayList<>();
    sequence.add(num);
    long current = num;

    while (true) {
        int pop = Long.bitCount(current);
        if (depthMap.containsKey(pop)) {
            int baseDepth = depthMap.get(pop);
            for (int i = 0; i < sequence.size(); i++) {
                depthMap.put(sequence.get(i), baseDepth + sequence.size() - i);
            }
            return depthMap.get(num);
        }
        sequence.add((long) pop);
        current = pop;
    }
}
