        if (depthCache.containsKey(num)) {
            return depthCache.get(num);
        }
        List<Long> sequence = new ArrayList<>();
        long current = num;
        while (!depthCache.containsKey(current)) {
            sequence.add(current);
            current = popcount(current);
        }
        int knownDepth = depthCache.get(current);
        for (int i = sequence.size() - 1; i >= 0; i--) {
            knownDepth++;
            depthCache.put(sequence.get(i), knownDepth);
        }
        return depthCache.get(num);
    }

    private static long popcount(long x) {
        long count = 0;
        while (x != 0) {
            count += x & 1;
            x >>>= 1;
        }
        return count;
    }
