            long k = query[3];
            long count = 0;
            for (int j = l; j <= r; j++) {
                long num = nums[j];
                int depth = getPopcountDepth(num, depthCache);
                if (depth == k) {
                    count++;
                }
            }
            answer[answerIdx++] = count;
        } else if (query[0] == 2) {
            // Type 2 query: update nums[idx] = val
