private static int getPopcountDepth(long x, HashMap<Long, Integer> depthCache) {
    if (depthCache.containsKey(x)) {
        return depthCache.get(x);
    }
    long current = x;
    int depth = 0;
    // We'll compute the sequence until we find a cached value
    // To avoid stack overflow for large sequences, we use iteration
    HashMap<Long, Integer> tempPath = new HashMap<>();
    while (true) {
        if (depthCache.containsKey(current)) {
            int cachedDepth = depthCache.get(current);
            // Update all nodes in tempPath with their correct depth
            for (long num : tempPath.keySet()) {
                depthCache.put(num, tempPath.get(num) + cachedDepth + 1);
            }
            return depth + cachedDepth;
        }
        tempPath.put(current, depth);
        long next = Long.bitCount(current);
        depth++;
        if (next == 1) {
            // Reached the end of the sequence
            for (long num : tempPath.keySet()) {
                depthCache.put(num, tempPath.get(num) + depth);
            }
