import java.util.*;

public static long[] solve(long[] nums, long[][] queries) {
    // Precompute popcount-depth for numbers up to 1e15
    // Since popcount-depth is logarithmic, we can memoize it
    Map<Long, Integer> depthCache = new HashMap<>();
    depthCache.put(1L, 0);

    List<Long> answerList = new ArrayList<>();

    // Process queries
    for (long[] query : queries) {
        if (query[0] == 1) {
            // Type 1 query: count nums[j] in [l, r] with depth == k
            int l = (int) query[1];
            int r = (int) query[2];
            long k = query[3];
            long count = 0;
            for (int j = l; j <= r; j++) {
                int depth = getPopcountDepth(nums[j], depthCache);
                if (depth == k) {
                    count++;
                }
            }
            answerList.add(count);
        } else if (query[0] == 2) {
            // Type 2 query: update nums[idx] to val
            int idx = (int) query[1];
            long val = query[2];
            nums[idx] = val;
        }
    }

    // Convert answerList to long[]
    long[] answer = new long[answerList.size()];
    for (int i = 0; i < answerList.size(); i++) {
        answer[i] = answerList.get(i);
    }
    return answer;
}

private static int getPopcountDepth(long x, Map<Long, Integer> depthCache) {
    if (depthCache.containsKey(x)) {
        return depthCache.get(x);
    }

    long current = x;
    List<Long> path = new ArrayList<>();
    while (!depthCache.containsKey(current)) {
        path.add(current);
        current = Long.bitCount(current);
    }

    int baseDepth = depthCache.get(current);
    for (int i = path.size() - 1; i >= 0; i--) {
        long num = path.get(i);
        depthCache.put(num, baseDepth + (path.size() - i));
    }

    return depthCache.get(x);
}
