public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        // Precompute popcount-depth for numbers up to 1e15, but it's not feasible to precompute all.
        // Instead, compute depth on the fly and memoize.
        Map<Long, Integer> depthCache = new HashMap<>();
        depthCache.put(1L, 0);

        List<Long> answerList = new ArrayList<>();

        for (long[] query : queries) {
            if (query[0] == 1) {
