                int count = 0;
                for (long j = l; j <= r; j++) {
                    int idx = (int) j;
                    long num = nums[idx];
                    int depth = getDepth(num, depthCache);
                    if (depth == k) {
                        count++;
                    }
                }
                answerList.add((long) count);
            } else if (query[0] == 2) {
                // Query type 2: update nums[idx] = val
                long idx = query[1];
                long val = query[2];
                nums[(int) idx] = val;
            }
        }

        long[] answer = new long[answerList.size()];
        for (int i = 0; i < answerList.size(); i++) {
            answer[i] = answerList.get(i);
        }
        return answer;
