private static int getPopcountDepth(long x, HashMap<Long, Integer> depthCache) {
    if (depthCache.containsKey(x)) {
        return depthCache.get(x);
    }

    long current = x;
    int depth = 0;
    // We'll compute the sequence until we hit a known value
    // To avoid stack overflow, we'll use iteration
    HashMap<Long, Integer> tempPath = new HashMap<>();
    while (true) {
        if (depthCache.containsKey(current)) {
            int knownDepth = depthCache.get(current);
            for (long num : tempPath.keySet()) {
                depthCache.put(num, tempPath.get(num) + knownDepth + 1);
            }
            return depth + knownDepth;
        }
        tempPath.put(current, depth);
        current = Long.bitCount(current);
        depth++;
    }
}
